// ── Node: Notion-Daten aufbereiten & Säulen normalisieren ──

const results = $input.first().json.results || [];
const today = new Date().toISOString().split('T')[0];

// 90-Tage-Grenze für "veröffentlicht"
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 90);

// Säulen-Normalisierung (Umlaut-Varianten → kanonische Form)
const saeuleMap = {
  'Saeule 1 - Persoenliche Erlebnisse': 'Säule 1 – Persönliche Erlebnisse',
  'Saeule 2 - Tipps und Methoden':      'Säule 2 – Tipps & Methoden',
  'Saeule 3 - Trends und Markt':        'Säule 3 – Trends & Markt'
};

function normSaeule(s) {
  return saeuleMap[s] || s || 'NICHT ZUGEORDNET';
}

function prop(page, key, type) {
  const p = page.properties?.[key];
  if (!p) return null;
  switch(type) {
    case 'title':   return p.title?.map(t => t.plain_text).join('') || '';
    case 'text':    return p.rich_text?.map(t => t.plain_text).join('') || '';
    case 'select':  return p.select?.name || '';
    case 'date':    return p.date?.start || null;
    case 'number':  return p.number ?? null;
    case 'checkbox':return p.checkbox ?? false;
    default:        return null;
  }
}

const alle = results.map(page => ({
  notion_id:       page.id,
  titel:           prop(page, 'Titel',          'title'),
  saeule:          normSaeule(prop(page, 'Säule', 'select')),
  typ:             prop(page, 'Typ',            'select'),
  hook:            prop(page, 'Hook',           'text'),
  kern_inhalt:     prop(page, 'Kern-Inhalt',    'text'),
  linkedin_post:   prop(page, 'LinkedIn-Post',  'text'),
  cta:             prop(page, 'CTA',            'text'),
  hashtags:        prop(page, 'Hashtags',       'text'),
  board_erwaehnung:prop(page, 'Board-Erwähnung','checkbox'),
  status:          prop(page, 'Status',         'select'),
  geplant_fuer:    prop(page, 'Geplant für',    'date'),
  kw:              prop(page, 'KW',             'number'),
  impressionen:    prop(page, 'Impressionen',   'number'),
  likes:           prop(page, 'Likes',          'number'),
  kommentare:      prop(page, 'Kommentare',     'number'),
  shares:          prop(page, 'Shares',         'number'),
  dms_leads:       prop(page, 'DMs / Leads',    'number')
}));

const veroeffentlicht = alle.filter(p => {
  if (p.status !== 'Veröffentlicht') return false;
  if (!p.geplant_fuer) return true;
  return new Date(p.geplant_fuer) >= cutoff;
});

const geplant = alle.filter(p =>
  ['Geplant','Erstellt','Freigegeben'].includes(p.status)
);

return [{ json: {
  audit_datum: today,
  veroeffentlichte_posts: veroeffentlicht,
  geplante_posts: geplant,
  gesamt_geladen: alle.length
}}];

// ── Node: Claude-Antwort parsen ──

const response = $input.first().json;

// Text-Block aus Anthropic-Response extrahieren
const contentBlocks = response.content || [];
const textBlock = contentBlocks.find(b => b.type === 'text');

if (!textBlock) {
  throw new Error('Keine Text-Antwort von Claude erhalten. Response: ' + JSON.stringify(response).substring(0, 500));
}

let rawText = textBlock.text.trim();

// Markdown-Codeblock-Wrapper entfernen (Fallback)
rawText = rawText.replace(/^```json\s*/i, '').replace(/\s*```$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  throw new Error('JSON-Parse-Fehler: ' + e.message + '\n\nRaw (erste 800 Zeichen):\n' + rawText.substring(0, 800));
}

const auditItems   = parsed.audit        || [];
const gesamtbefund = parsed.gesamtbefund || {};
const todoListe    = parsed.todo_liste   || [];
const neuePosts    = parsed.neue_posts   || [];

// Stats für Logging
console.log(`Audit: ${auditItems.length} Posts geprüft | Neue Posts: ${neuePosts.length} | ToDos: ${todoListe.length}`);

return [{ json: {
  audit:        auditItems,
  gesamtbefund: gesamtbefund,
  todo_liste:   todoListe,
  neue_posts:   neuePosts,
  meta: {
    audit_datum:    $('Code: Prompt aufbauen').first().json.audit_datum,
    posts_geprueft: auditItems.length,
    posts_generiert: neuePosts.length
  }
}}];

// ── Node: Neue Posts für Notion vorbereiten ──
// Erstellt einen Item pro Post mit korrekten Datumsfeldern

const data = $input.first().json;
const neuePosts = data.neue_posts || [];

if (neuePosts.length === 0) {
  throw new Error('Keine neuen Posts von Claude generiert.');
}

// Nächsten Montag berechnen
function naechsterMontag() {
  const heute = new Date();
  const tag = heute.getDay(); // 0=So, 1=Mo
  const diff = (tag === 0) ? 1 : (tag === 1 ? 7 : 8 - tag);
  const montag = new Date(heute);
  montag.setDate(heute.getDate() + diff);
  montag.setHours(0, 0, 0, 0);
  return montag;
}

// Mo/Mi/Fr-Sequenz generieren
function genDaten(anzahl) {
  const daten = [];
  let basis = naechsterMontag();
  for (let i = 0; i < anzahl; i++) {
    daten.push(basis.toISOString().split('T')[0]);
    const tag = basis.getDay();
    if      (tag === 1) basis.setDate(basis.getDate() + 2); // Mo → Mi
    else if (tag === 3) basis.setDate(basis.getDate() + 2); // Mi → Fr
    else if (tag === 5) basis.setDate(basis.getDate() + 3); // Fr → Mo
    else                basis.setDate(basis.getDate() + 1);
  }
  return daten;
}

// ISO KW berechnen
function getKW(iso) {
  const d = new Date(iso);
  d.setHours(12);
  d.setDate(d.getDate() + 4 - (d.getDay() || 7));
  const yearStart = new Date(d.getFullYear(), 0, 1);
  return Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
}

const daten = genDaten(neuePosts.length);

return neuePosts.map((post, i) => ({ json: {
  titel:            post.titel            || 'Kein Titel',
  saeule:           post.saeule           || 'Säule 1 – Persönliche Erlebnisse',
  typ:              post.typ              || '',
  hook:             post.hook             || '',
  kern_inhalt:      post.kern_inhalt      || '',
  linkedin_post:    post.linkedin_post    || '',
  cta:              post.cta             || '',
  hashtags:         post.hashtags         || '',
  board_erwaehnung: post.board_erwaehnung ?? false,
  geplant_fuer:     daten[i],
  kw:               getKW(daten[i]),
  status:           'Geplant',
  quelle:           'n8n-Monatsgenerierung'
}}));

