// ── Node: Audit-Zusammenfassung loggen ──
// Gibt eine lesbare Zusammenfassung aus für das n8n Execution Log

const parseNode = $('Code: Claude-Antwort parsen').first().json;
const g = parseNode.gesamtbefund || {};
const todos = parseNode.todo_liste || [];
const audit = parseNode.audit || [];

const failedPosts = audit.filter(a => a.pass_fail === 'FAIL').map(a => a.titel);
const passedPosts = audit.filter(a => a.pass_fail === 'PASS').map(a => a.titel);

const summary = [
  `=== BLBoardSolutions LinkedIn Audit – ${parseNode.meta?.audit_datum || 'heute'} ===`,
  ``,
  `GEPRÜFTE POSTS: ${audit.length} (✅ ${passedPosts.length} PASS | ❌ ${failedPosts.length} FAIL)`,
  `NEUE POSTS GENERIERT: ${parseNode.neue_posts?.length || 0}`,
  ``,
  `SÄULEN-VERTEILUNG:`,
  `  Säule 1: ${g.saeulen_verteilung_prozent?.saeule_1 || 0}%`,
  `  Säule 2: ${g.saeulen_verteilung_prozent?.saeule_2 || 0}%`,
  `  Säule 3: ${g.saeulen_verteilung_prozent?.saeule_3 || 0}%`,
  `  Spotlight: ${g.saeulen_verteilung_prozent?.spotlight || 0}%`,
  `  Unklar: ${g.saeulen_verteilung_prozent?.unklar || 0}%`,
  ``,
  `SAVE-ASSET-QUOTE: ${g.save_asset_quote_prozent || 0}% (Ziel: ≥50%)`,
  `CLUSTER-DRIFT-RISIKO: ${g.cluster_drift_risiko || 'n/a'}`,
  ``,
  `FAILED POSTS: ${failedPosts.length > 0 ? failedPosts.join(', ') : 'keine'}`,
  ``,
  `TOP-3 TO-DOS:`,
  ...todos.slice(0, 3).map(t => `  ${t.rang}. [${t.hebelwirkung}] ${t.massnahme}`),
  ``,
  `PERFORMANCE-INSIGHT:`,
  `  ${g.performance_insight || 'keine Daten'}`,
].join('\n');

console.log(summary);

return [{ json: { summary, meta: parseNode.meta } }];
